const body = $input.first()?.json?.body || $input.first()?.json || {};
let action = (body.action || 'list').toLowerCase();
const actionMap = { 'get': 'list', 'post': 'create', 'put': 'update', 'patch': 'update', 'del': 'delete' };
action = actionMap[action] || action;

// Normalize: accept both 'title' and 'item' fields
if (body.title && !body.item) body.item = body.title;

if (action === 'create') {
  const item = (body.item || '').trim();
  if (!item || item.length < 3) {
    return [{ json: { action: '_validation_error', body, error: 'Item text is required (min 3 characters)', field: 'item' } }];
  }
  if (body.deadline || body.due) {
    const d = new Date(body.deadline || body.due);
    if (isNaN(d.getTime())) {
      return [{ json: { action: '_validation_error', body, error: 'Invalid deadline date format. Use YYYY-MM-DD.', field: 'deadline' } }];
    }
    body.deadline = body.deadline || body.due;
  }
}
if (action === 'update') {
  if (!body.id) {
    return [{ json: { action: '_validation_error', body, error: 'Item ID is required for update', field: 'id' } }];
  }
  if (!body.status) {
    return [{ json: { action: '_validation_error', body, error: 'Status is required for update', field: 'status' } }];
  }
}
if (action === 'delete') {
  if (!body.id) {
    return [{ json: { action: '_validation_error', body, error: 'Item ID is required for delete', field: 'id' } }];
  }
}

const indexMap = { 'list': 0, 'create': 1, 'bulk_create': 2, 'update': 3, 'delete': 4, 'ics': 5, 'digest': 6 };
const actionIndex = indexMap[action] ?? 0;
return [{ json: { action, actionIndex, body } }];

// This node returns the bulk items for the respond node to pick up
const body = $('Route Action').first()?.json?.body || {};
const items = body.items || [];
return [{ json: { inserted: items.length, items } }];

const body = $('Route Action').first().json.body;
const item = body.item_data || body;
const title = item.item || 'GDA Action Item';
const owner = item.owner || 'GDA Team';
const deadline = item.deadline || new Date(Date.now() + 14*24*60*60*1000).toISOString().split('T')[0];

const dtStart = deadline.replace(/-/g,'') + 'T090000';
const dtEnd = deadline.replace(/-/g,'') + 'T100000';
const now = new Date().toISOString().replace(/[-:.]/g,'').substring(0,15) + 'Z';
const uid = 'gda-action-' + Date.now() + '@csr-llc.tech';

const ics = [
  'BEGIN:VCALENDAR',
  'VERSION:2.0',
  'PRODID:-//GDA//Action Items//EN',
  'BEGIN:VEVENT',
  `UID:${uid}`,
  `DTSTART:${dtStart}`,
  `DTEND:${dtEnd}`,
  `DTSTAMP:${now}`,
  `SUMMARY:${title}`,
  `DESCRIPTION:Owner: ${owner}\\nSource: ${item.source_meeting || 'GDA Platform'}`,
  `ORGANIZER:mailto:shawn.seffernick175@gmail.com`,
  'STATUS:CONFIRMED',
  `CATEGORIES:GDA,Action Item`,
  'BEGIN:VALARM',
  'TRIGGER:-P1D',
  'ACTION:DISPLAY',
  'DESCRIPTION:GDA Action Item Due Tomorrow',
  'END:VALARM',
  'END:VEVENT',
  'END:VCALENDAR'
].join('\r\n');

const ics_base64 = Buffer.from(ics).toString('base64');

return [{
  json: {
    ics_data: 'data:text/calendar;base64,' + ics_base64,
    filename: title.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 50) + '.ics',
    status: 'ok'
  }
}];

// Weekly digest - items passed from List Items query
// Note: This route needs items from the database
// For now, return a template that the frontend can populate
const now = new Date();
return [{
  json: {
    action: 'digest',
    email_to: 'shawn.seffernick175@gmail.com',
    email_subject: 'GDA Action Items Weekly Digest — ' + now.toLocaleDateString(),
    note: 'Digest requires a list query first. Use action=list to get items with overdue_count, then format digest client-side.',
    status: 'ok'
  }
}];

if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];
